    public function parse_market($market): array {
        //
        //    {
        //        "instrument" => "BTC_USDT_Perp",
        //        "instrument_hash" => "0x030501",
        //        "base" => "BTC",
        //        "quote" => "USDT",
        //        "kind" => "PERPETUAL",
        //        "venues" => array(
        //            "ORDERBOOK",
        //            "RFQ"
        //        ),
        //        "settlement_period" => "PERPETUAL",
        //        "base_decimals" => 9,
        //        "quote_decimals" => 6,
        //        "tick_size" => "0.1",
        //        "min_size" => "0.001",
        //        "create_time" => "1768040726362828205",
        //        "max_position_size" => "1000.0",
        //        "funding_interval_hours" => 8,
        //        "adjusted_funding_rate_cap" => "0.3",
        //        "adjusted_funding_rate_floor" => "-0.3",
        //        "min_notional" => "100.0"
        //    }
        //
        $marketId = $this->safe_string($market, 'instrument');
        $baseId = $this->safe_string($market, 'base');
        $quoteId = $this->safe_string($market, 'quote');
        $settleId = $quoteId;
        $base = $this->safe_currency_code($baseId);
        $quote = $this->safe_currency_code($quoteId);
        $settle = $this->safe_currency_code($settleId);
        $symbol = $base . '/' . $quote . ':' . $settle;
        $type = null;
        $typeRaw = $this->safe_string($market, 'kind');
        if ($typeRaw === 'PERPETUAL') {
            $type = 'swap';
        }
        $isSpot = ($type === 'spot');
        $isSwap = ($type === 'swap');
        $isFuture = ($type === 'future');
        $isContract = $isSwap || $isFuture;
        return array(
            'id' => $marketId,
            'symbol' => $symbol,
            'base' => $base,
            'quote' => $quote,
            'settle' => $settle,
            'baseId' => $baseId,
            'quoteId' => $quoteId,
            'settleId' => $settleId,
            'type' => $type,
            'spot' => $isSpot,
            'margin' => false,
            'swap' => $isSwap,
            'future' => $isFuture,
            'option' => false,
            'active' => null, // todo => ask support to add
            'contract' => $isContract,
            'linear' => $isSwap ? true : null,
            'inverse' => $isSwap ? false : null,
            'contractSize' => $this->parse_number('1'), // tbd, vague response from support
            'expiry' => null,
            'expiryDatetime' => null,
            'strike' => null,
            'optionType' => null,
            'precision' => array(
                'amount' => $this->safe_number($market, 'min_size'), // confirmed, not 'base_decimals'
                'price' => $this->safe_number($market, 'tick_size'),
                'base' => $this->parse_number($this->parse_precision($this->safe_string($market, 'base_decimals'))),
                'quote' => $this->parse_number($this->parse_precision($this->safe_string($market, 'quote_decimals'))),
            ),
            'limits' => array(
                'leverage' => array(
                    'min' => null,
                    'max' => null,
                ),
                'amount' => array(
                    'min' => $this->safe_number($market, 'min_size'),
                    'max' => $this->safe_number($market, 'max_position_size'),
                ),
                'price' => array(
                    'min' => null,
                    'max' => null,
                ),
                'cost' => array(
                    'min' => $this->safe_number($market, 'min_notional'),
                    'max' => null,
                ),
            ),
            'created' => $this->safe_integer_product($market, 'create_time', 0.000001),
            'info' => $market,
        );
    }

