            //                "is_taker_buyer" => false,
            //                "size" => "23.73",
            //                "price" => "3089.88",
            //                "mark_price" => "3089.360002315",
            //                "index_price" => "3090.443723246",
            //                "interest_rate" => "0.0",
            //                "forward_price" => "0.0",
            //                "trade_id" => "64796657-1",
            //                "venue" => "ORDERBOOK",
            //                "is_rpi" => false
            //            ),
            //            ...
            //
            $result = $this->safe_list($response, 'result', array());
            return $this->parse_trades($result, $market, $since, $limit);
        }) ();
    }

