        //                "funding_rate_8_h_avg" => "-0.0038",
        //                "funding_interval_hours" => "0"
        //            ),
        //
        $marketId = $this->safe_string($rawItem, 'instrument');
        $ts = $this->safe_integer_product($rawItem, 'funding_time', 0.000001);
        return array(
