    public function convert_to_big_int_custom($x) {
        return intval($x);
    }

    public function eip_message_for_order($order, $structureType) {
        $priceMultiplier = '1000000000';
        $orderLegs = $this->safe_list($order, 'legs', array());
        $legs = array();
        for ($i = 0; $i < count($orderLegs); $i++) {
            $leg = $orderLegs[$i];
            $market = $this->market($leg['instrument']);
            $bigInt10 = $this->convert_to_big_int_custom('10');
            $precisionValue = $this->precision_from_string($this->safe_string($market['precision'], 'base'));
            $precisionValueStr = (string) $precisionValue;
            $sizeMultiplier = pow($bigInt10, $this->convert_to_big_int_custom($precisionValueStr));
            $size = $leg['size'];
            $sizeParts = explode('.', $size);
            $sizeDec = $this->safe_string($sizeParts, 1, '');
            $sizeDecLength = strlen($sizeDec) + 0; // php tr
            $sizeDecLengthStr = (string) $sizeDecLength;
            $sizeInteger = $this->convert_to_big_int_custom(str_replace('.', '', $size)) * $sizeMultiplier / (pow($bigInt10, $this->convert_to_big_int_custom($sizeDecLengthStr)));
            $legOrder = array(
                'assetID' => $market['info']['instrument_hash'],
                'contractSize' => $this->parse_to_int($sizeInteger),
                'isBuyingContract' => $leg['is_buying_asset'],
            );
            $limitPrice = $this->safe_string($leg, 'limit_price');
            if ($this->omit_zero($limitPrice) !== null) {
                $price = $leg['limit_price'];
                $limitParts = explode('.', $price);
                $limitDec = $this->safe_string($limitParts, 1, '');
                $limitDecLength = strlen($limitDec) + 0; // php tr
                $limitDecLengthStr = (string) $limitDecLength;
                $powerNum = $limitDecLengthStr === '0' ? 0 : $this->convert_to_big_int_custom($limitDecLengthStr);
                $priceInteger = ($this->convert_to_big_int_custom(str_replace('.', '', $price)) * $this->convert_to_big_int_custom($priceMultiplier) / (pow($bigInt10, $powerNum)));
                $legOrder['limitPrice'] = $this->parse_to_int($priceInteger);
            } else {
                $legOrder['limitPrice'] = 0; // should be zero to validate type-check
            }
            $legs[] = $legOrder;
        }
        $returnValue = array(
            'subAccountID' => $order['sub_account_id'],
            'isMarket' => $order['is_market'],
            'timeInForce' => $this->time_in_force_to_int($order['time_in_force']),
            'postOnly' => $order['post_only'],
            'reduceOnly' => $order['reduce_only'],
            'legs' => $legs,
            'nonce' => $order['signature']['nonce'],
            'expiration' => $order['signature']['expiration'],
        );
        if ($structureType === 'EIP712_ORDER_WITH_BUILDER_TYPE' && $this->safe_bool($this->options, 'builderFee', true)) {
            $returnValue['builder'] = $order['builder'];
            $returnValue['builderFee'] = $this->parse_to_int($this->convert_to_big_int_custom($this->fee_amount_multiplier()) * floatval($order['builder_fee'])); // the $order is matter for Multiply in go, b must be float64 otherwise the value would be 0
        }
        return $returnValue;
    }

    public function fetch_my_trades(?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()) {
        return Async\async(function () use ($symbol, $since, $limit, $params) {
            /**
             * fetch all trades made by the user
             *
             * @see https://api-docs.grvt.io/trading_api/#fill-history
             *
             * @param {string} [$symbol] unified $market $symbol
             * @param {int} [$since] the earliest time in ms to fetch trades for
             * @param {int} [$limit] the maximum number of trade structures to retrieve
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {int} [$params->until] timestamp in ms of the latest item
             * @param {boolean} [$params->paginate] default false, when true will automatically $paginate by calling this endpoint multiple times. See in the docs all the [available parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-$params)
             * @return {Trade[]} a list of ~@link https://docs.ccxt.com/#/?id=trade-structure trade structures~
             */
            Async\await($this->load_markets_and_sign_in());
            $paginate = false;
            list($paginate, $params) = $this->handle_option_and_params($params, 'fetchMyTrades', 'paginate');
            if ($paginate) {
                return Async\await($this->fetch_paginated_call_dynamic('fetchMyTrades', $symbol, $since, $limit, $params));
            }
            $request = array(
                'sub_account_id' => $this->get_sub_account_id($params),
            );
            $market = null;
            if ($symbol !== null) {
                $market = $this->market($symbol);
                $request['base'] = array();
                $request['base'][] = $market['baseId'];
                $request['quote'] = array();
                $request['quote'][] = $market['quoteId'];
            }
            if ($limit !== null) {
                $request['limit'] = min ($limit, 1000);
            }
            list($request, $params) = $this->handle_until_option_string('end_time', $request, $params, 1000000);
            if ($since !== null) {
                $request['start_time'] = $this->number_to_string($since * 1000000);
            }
            $response = Async\await($this->privateTradingPostFullV1FillHistory ($this->extend($request, $params)));
