        //                "cumulative_realized_funding_payment" => "0.033862"
        //            }
        //
        $marketId = $this->safe_string($position, 'instrument');
        $timestamp = $this->safe_integer_product($position, 'event_time', 0.000001);
        $sizeRaw = $this->safe_string($position, 'size');
        $isLong = (Precise::string_ge($sizeRaw, '0'));
        $side = $isLong ? 'long' : 'short';
        return $this->safe_position(array(
            'info' => $position,
            'id' => null,
            'symbol' => $this->safe_symbol($marketId, $market),
            'notional' => $this->parse_number(Precise::string_abs($this->safe_string($position, 'notional'))),
            'marginMode' => null,
            'liquidationPrice' => $this->safe_number($position, 'est_liquidation_price'),
            'entryPrice' => $this->safe_number($position, 'entry_price'),
            'unrealizedPnl' => $this->safe_number($position, 'unrealized_pnl'),
            'realizedPnl' => $this->safe_number($position, 'realized_pnl'),
            'percentage' => null,
            'contracts' => $this->parse_number(Precise::string_abs($sizeRaw)),
            'markPrice' => $this->safe_number($position, 'mark_price'),
            'lastPrice' => null,
            'side' => $side,
            'hedged' => null,
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'lastUpdateTimestamp' => $this->safe_integer($position, 'lastUpdateTime'),
            'maintenanceMargin' => $this->safe_number($position, 'maintenanceMargin'),
            'maintenanceMarginPercentage' => null,
            'collateral' => null,
            'initialMargin' => $this->safe_number($position, 'initialMargin'),
            'initialMarginPercentage' => null,
            'leverage' => $this->safe_number($position, 'leverage'),
            'marginRatio' => null,
            'stopLossPrice' => null,
            'takeProfitPrice' => null,
        ));
    }

